class Solution {
    public int addMinimum(String word) {
        int count = 0;
        int aCount = 0;
        for (char c : word.toCharArray()) {
            if (c == 'a') {
                aCount++;
            } else if (c == 'b') {
                count += Math.max(0, aCount - 1);
                aCount = 0;
            } else {
                count += aCount + 1;
            }
        }
        return count + Math.max(0, aCount * 2);
    }
}
